(function(){"use strict";const M=window.OrbArena.CharacterMechanics;
  M.register("glitch",{active(w,s,t,c){if(c.random.chance(.5))c.teleport(w,s,c.random.range(70,890),c.random.range(70,470));else{const v=s.damage;s.damage=t.damage;t.damage=v;}return 5;},update(w,s,t,dt,c){if(c.random.chance(dt*.04))s.ai.orbit*=-1;},ultimate(w,s,t,c){for(let i=0;i<6;i++)c.schedule(w,i*.35,()=>{c.teleport(w,s,c.random.range(60,900),c.random.range(60,480));c.burst(w,s,t,{radial:true,count:5,damage:7,bounces:2,color:s.glowColor});});}});
  function roll(w,s,t,c){const n=1+Math.floor(c.random.next()*6);if(n===1)c.damage(w,s,t,22,"dice");if(n===2)c.heal(s,24);if(n===3)s.setStatus("haste",5,.4);if(n===4)c.clone(w,s,{life:6,damageScale:.4});if(n===5)c.radial(w,s,t,180,16,330,"dice-blast");if(n===6)s.setStatus("slow",2,.65);return n;}
  M.register("dice",{active(w,s,t,c){s.characterState.data.face=roll(w,s,t,c);return 5.5;},receive(w,s,a,e,c){if(e.damage>15&&c.random.chance(.3))roll(w,s,a,c);},ultimate(w,s,t,c){roll(w,s,t,c);roll(w,s,t,c);}});
  M.register("wildcard",{active(w,s,t,c){const list=[()=>c.heal(s,20),()=>c.shield(s,25),()=>c.clone(w,s,{life:5}),()=>c.burst(w,s,t,{count:7,damage:7}),()=>c.teleport(w,s,t.x-50,t.y)];c.random.pick(list)();return 5;},ultimate(w,s,t,c){c.heal(s,20);c.shield(s,25);c.clone(w,s,{life:7});c.burst(w,s,t,{radial:true,count:12,damage:8,bounces:1});s.setStatus("haste",7,.3);}});
  M.register("chaos",{active(w,s,t,c){const n=Math.floor(c.random.next()*4);if(n===0)w.arena.gravity=c.random.range(-120,120);if(n===1)c.slowGame(c.random.range(.45,1.35),4,s);if(n===2)w.arena.rotationForce=c.random.range(-380,380),w.arena.rotationTimer=5;if(n===3){s.ai.orbit*=-1;t.ai.orbit*=-1;}return 6;},ultimate(w,s,t,c){for(let i=0;i<8;i++)c.schedule(w,i*.5,()=>{c.radial(w,s,t,c.random.range(100,300),c.random.range(5,15),c.random.range(-350,450),"chaos",true);c.burst(w,s,t,{radial:true,count:5,damage:5,bounces:3});});}});
}());
